import{t as e}from"./chunk-BLhQqvoO.js";var t=e(),n={publishing_date:`2025-03-11`,title:`Can I have interactive python pages ?`,category:`quantum`,secondaryCategory:`webdev`,description:`I explore the future of interactive content with Python running directly in browsers. Tools like Pyodide and JupyterLite enable portable, installation-free data science.`};function r(e){let n={a:`a`,code:`code`,em:`em`,li:`li`,p:`p`,ul:`ul`,...e.components};return(0,t.jsxs)(t.Fragment,{children:[(0,t.jsxs)(n.p,{children:[`_The original post on mirror can be found `,(0,t.jsx)(n.a,{href:`https://mirror.xyz/fretchen.eth/iglgKZeAeHcUc_-Ya9cjQQ1vUNqhJTRUswredn-53e8?referrerAddress=0x073f26F0C3FC100e7b075C3DC3cDE0A777497D20`,children:`here`}),`._`]}),`
`,(0,t.jsxs)(n.p,{children:[`One of my main motivations to start this website was to consolidate different lectures, writings and other things that accumulated over the years in different places. The first project was to actually move my AMO lectures. This is now finished and can be found over `,(0,t.jsx)(n.a,{href:`https://www.fretchen.eu/amo`,children:`here`}),`. I started with this as it was a really simple test case without anything interactive components.`]}),`
`,(0,t.jsxs)(n.p,{children:[`However, I have a few more projects which are really based on `,(0,t.jsx)(n.a,{href:`https://jupyter.org/`,children:`jupyter`}),` notebooks. jupyter notebooks are just a fantastic tool to combine notes with simple visualizations and the `,(0,t.jsx)(n.a,{href:`https://jupyterbook.org`,children:`jupyter book`}),` project is really a great way to publish them. The only "annoying" drawback has been for years that you have to somehow download the notebook and run it locally or go into some service like `,(0,t.jsx)(n.a,{href:`https://mybinder.org/`,children:`binder`}),`.`]}),`
`,(0,t.jsxs)(n.p,{children:[`The rise of python in the browser actually promises to changes that at some point. What does this mean ? Projects like `,(0,t.jsx)(n.a,{href:`https://github.com/jupyterlite`,children:`jupyterlite`}),` allow you to run the full jupyter experience without any installation. And tools like `,(0,t.jsx)(n.a,{href:`https://pyodide.org/en/stable/`,children:`pyodide`}),` bring python directly into the brower. Just python programming without the cloud, or any installation. It all just runs in the browser. This would make the jupyter notebooks that I loved so extremely portable. And actually, there are now package that attempt to connect this directly to `,(0,t.jsx)(n.a,{href:`https://github.com/elilambnz/react-py`,children:`react`}),`. If this worked out I would have:`]}),`
`,(0,t.jsxs)(n.ul,{children:[`
`,(0,t.jsx)(n.li,{children:`A blog that is written in markdown.`}),`
`,(0,t.jsx)(n.li,{children:`The possibility to add small python snippets directly into the blog.`}),`
`,(0,t.jsx)(n.li,{children:`All of this part of a website without the need to install anything.`}),`
`]}),`
`,(0,t.jsxs)(n.p,{children:[`I gave all of this a try and `,(0,t.jsx)(n.code,{children:`react-py`}),` looked particularly interesting. However, the ecosystem still seems fairly young and it was super painful to get even the simplest examples to run. I must admit that I gave up for the moment, when I understood that pyodide and hence `,(0,t.jsx)(n.code,{children:`react-py`}),` does always require a `,(0,t.jsx)(n.a,{href:`https://pyodide.org/en/latest/usage/working-with-bundlers.html`,children:`build for tests`}),`. Having it in `,(0,t.jsx)(n.code,{children:`dev`}),` would have been a minimum to make it an enjoyable experience.`]}),`
`,(0,t.jsxs)(n.p,{children:[`So for the moment I will most likely just transform the jupyter notebooks into react / plein markdown and then see how the ecosystem evolves. But kudos to the people behind `,(0,t.jsx)(n.em,{children:`python-in-the-browser`}),`. This is a super exciting development for all kind of data science and will make the ecosystem much more decentralized and accessible. Any suggestions or additional information ? Then just leave them in the comments below.`]})]})}function i(e={}){let{wrapper:n}=e.components||{};return n?(0,t.jsx)(n,{...e,children:(0,t.jsx)(r,{...e})}):r(e)}export{i as default,n as frontmatter};